// 월간 집계 통계 및 LLM 프롬프트 생성
const items = $input.all();

if (!items.length) {
  return [{ json: { skip: true } }];
}

const now = new Date();
const monthStart = new Date(now.getFullYear(), now.getMonth() - 1, 1);
const monthStartISO = monthStart.toISOString();
const monthName = monthStart.toLocaleDateString('ko-KR', { year: 'numeric', month: 'long' });

const systemSummary = {};
items.forEach(item => {
  const d = item.json;
  if (!systemSummary[d.system_name]) {
    systemSummary[d.system_name] = {
      system_id: d.system_id,
      display_name: d.display_name,
      total_anomaly_hours: 0,
      worst_severity: 'normal',
      trends: []
    };
  }
  const s = systemSummary[d.system_name];
  s.total_anomaly_hours += parseFloat(d.total_anomaly_hours) || 0;
  if (d.worst_severity === 'critical' || (d.worst_severity === 'warning' && s.worst_severity !== 'critical')) {
    s.worst_severity = d.worst_severity;
  }
  if (d.trend_summary) s.trends.push(d.trend_summary.substring(0, 100));
});

const systemLines = Object.values(systemSummary)
  .sort((a, b) => b.total_anomaly_hours - a.total_anomaly_hours)
  .slice(0, 10)
  .map(s => `- ${s.display_name}: 이상 ${Math.round(s.total_anomaly_hours)}시간, 심각도: ${s.worst_severity}${s.trends.length ? ', 주요추세: ' + s.trends[0].substring(0, 80) : ''}`);

const llmPrompt = `${monthName} 전체 시스템 모니터링 월간 집계입니다.

[시스템별 월간 현황]
${systemLines.join('\n')}

총 ${Object.keys(systemSummary).length}개 시스템. 이번 달의 전반적인 시스템 안정성, 주목할 만한 이슈, 다음 달 주의사항을 한국어로 3-4 문장으로 요약해 주세요.`;

const monthlyMetricsJson = JSON.stringify({
  month: monthName,
  system_count: Object.keys(systemSummary).length,
  total_anomaly_hours: Object.values(systemSummary).reduce((a, s) => a + s.total_anomaly_hours, 0),
  critical_systems: Object.values(systemSummary).filter(s => s.worst_severity === 'critical').length
});

return [{
  json: {
    month_start_iso: monthStartISO,
    month_name: monthName,
    llm_prompt: llmPrompt,
    monthly_metrics_json: monthlyMetricsJson,
    system_count: Object.keys(systemSummary).length,
    skip: false
  }
}];

const llmResp = $input.first().json;
const prevData = $('월간 집계 계산 및 LLM 프롬프트 생성').first().json;

const llmSummary = llmResp?.choices?.[0]?.message?.content 
  || llmResp?.response 
  || llmResp?.content 
  || '월간 요약 생성 실패';

const metricsObj = JSON.parse(prevData.monthly_metrics_json || '{}');

const now = new Date();
const monthEnd = new Date(now.getFullYear(), now.getMonth(), 0);

const card = {
  type: 'message',
  attachments: [{
    contentType: 'application/vnd.microsoft.card.adaptive',
    content: {
      '$schema': 'http://adaptivecards.io/schemas/adaptive-card.json',
      type: 'AdaptiveCard',
      version: '1.4',
      body: [
        { type: 'TextBlock', text: `📅 월간 모니터링 리포트: ${prevData.month_name}`, weight: 'Bolder', size: 'Medium' },
        { type: 'TextBlock', text: llmSummary, wrap: true },
        {
          type: 'FactSet',
          facts: [
            { title: '모니터링 시스템', value: `${metricsObj.system_count || 0}개` },
            { title: '총 이상 발생',    value: `${Math.round(metricsObj.total_anomaly_hours || 0)}시간` },
            { title: 'Critical 시스템', value: `${metricsObj.critical_systems || 0}개` }
          ]
        }
      ]
    }
  }]
};

return [{
  json: {
    ...prevData,
    llm_summary: llmSummary,
    month_end_iso: monthEnd.toISOString(),
    teams_card: JSON.stringify(card)
  }
}];
